const input = $input.first().json;
// On ne garde ici QUE les mots-clés pour l'instant
return input.output.keywords.map(kw => ({ json: { keyword: kw } }));

// 1. Récupérer les mots-clés du batch actuel (25 items)
const batchItems = $input.all();
const keywordsList = batchItems.map(item => item.json.keyword);

// 2. Récupérer le contexte une seule fois (depuis le nœud source, ex: "Analyse Image")
const globalData = $("Edit Fields").first().json;

return {
  Theme: globalData.Theme,
  Niche: globalData.Niche,
  ProductType: globalData.ProductType,
  keywordsBatch: keywordsList // Un tableau de 25 mots-clés
};

const input = $input.first().json;
const keywords = input.output.keywords;
const batchSize = 25;
const batches = [];

// On découpe en paquets de 25
for (let i = 0; i < keywords.length; i += batchSize) {
    batches.push({
        json: {
            Theme: input.Theme,
            Niche: input.Niche,
            ProductType: input.ProductType,
            keywordsBatch: keywords.slice(i, i + batchSize)
        }
    });
}

return batches;

// On récupère tous les batches (les 8 items)
const allItems = $input.all();
let combinedKeywords = [];

// On boucle sur chaque batch pour extraire les keywords scorés
for (const item of allItems) {
    if (item.json.output && item.json.output.keywords) {
        combinedKeywords = combinedKeywords.concat(item.json.output.keywords);
    }
}

// On renvoie un objet unique contenant la liste totale
return {
    total_keywords: combinedKeywords.length,
    keywords: combinedKeywords
};
